/**
 * DonutChart.jsx
 * ─────────────────────────────────────────────────────────────
 * Gráfica de dona para gastos por categoría.
 * Usa Chart.js con colores del tema y tooltips personalizados.
 *
 * Props:
 *   data — { [categoria]: monto } (objeto de byCategory del backend)
 */

import { useEffect, useRef } from 'react'
import { Chart, ArcElement, Tooltip, Legend, DoughnutController } from 'chart.js'
import { formatCurrency } from '../../../utils/formatCurrency'

// Registrar solo los módulos necesarios (tree-shaking)
Chart.register(ArcElement, Tooltip, Legend, DoughnutController)

// Paleta de colores accesible y elegante
const PALETTE = [
  '#16a34a', '#2563eb', '#d97706', '#dc2626',
  '#7c3aed', '#0891b2', '#be185d', '#65a30d',
]

const CATEGORY_LABELS = {
  alimentación:    '🛒 Alimentación',
  transporte:      '🚗 Transporte',
  vivienda:        '🏠 Vivienda',
  salud:           '💊 Salud',
  entretenimiento: '🎬 Entretenimiento',
  educación:       '📚 Educación',
  ropa:            '👕 Ropa',
  otros:           '📦 Otros',
}

export default function DonutChart({ data = {} }) {
  const canvasRef = useRef(null)
  const chartRef  = useRef(null)

  useEffect(() => {
    if (!canvasRef.current) return

    const labels  = Object.keys(data)
    const values  = Object.values(data)

    // Destruir instancia anterior para evitar memory leaks
    if (chartRef.current) {
      chartRef.current.destroy()
    }

    chartRef.current = new Chart(canvasRef.current, {
      type: 'doughnut',
      data: {
        labels: labels.map((l) => CATEGORY_LABELS[l] || l),
        datasets: [{
          data:            values,
          backgroundColor: PALETTE.slice(0, labels.length),
          borderWidth:     0,
          hoverOffset:     8,
        }],
      },
      options: {
        responsive:          true,
        maintainAspectRatio: true,
        cutout:              '68%',
        plugins: {
          legend: {
            position: 'bottom',
            labels: {
              padding:    16,
              usePointStyle: true,
              pointStyleWidth: 8,
              font:       { size: 12, family: 'DM Sans' },
              color:      getComputedStyle(document.documentElement)
                            .getPropertyValue('--text-secondary').trim(),
            },
          },
          tooltip: {
            callbacks: {
              label: (ctx) => ` ${formatCurrency(ctx.raw)}`,
            },
            backgroundColor: getComputedStyle(document.documentElement)
                               .getPropertyValue('--surface-card').trim(),
            titleColor: getComputedStyle(document.documentElement)
                         .getPropertyValue('--text-primary').trim(),
            bodyColor:  getComputedStyle(document.documentElement)
                         .getPropertyValue('--text-secondary').trim(),
            borderColor: getComputedStyle(document.documentElement)
                          .getPropertyValue('--border-default').trim(),
            borderWidth: 1,
            padding:     12,
          },
        },
      },
    })

    // Cleanup al desmontar
    return () => {
      if (chartRef.current) chartRef.current.destroy()
    }
  }, [data])

  if (!Object.keys(data).length) {
    return (
      <div style={{ textAlign: 'center', padding: '40px 0', color: 'var(--text-tertiary)', fontSize: '0.875rem' }}>
        Sin datos para mostrar
      </div>
    )
  }

  return (
    <div style={{ maxWidth: 340, margin: '0 auto' }}>
      <canvas ref={canvasRef} />
    </div>
  )
}
